#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a, b;
        scanf("%d %d", &a, &b);
        if (a >= b) printf("%d\n", a);
        else printf("%d\n", b);
    }
    return 0;
}

